  1688→      if (pinch.pointers.size === 2) {
  1689→        // Stop pan and momentum when pinch starts
  1690→        stopMomentum();
  1691→        stopZoomAnimation();
  1692→        canvasStore.dispatch(canvasActions.viewport.endPan());
  1693→
  1694→        const pointers = Array.from(pinch.pointers.values());
  1695→        const dx = pointers[0].x - pointers[1].x;
  1696→        const dy = pointers[0].y - pointers[1].y;
  1697→        pinch.initialDistance = Math.sqrt(dx * dx + dy * dy);
  1698→        pinch.initialZoom = zoom;
  1699→        // Get camera position from store (always current, no stale closures)
  1700→        const currentCamera = canvasStore.getState().viewport.camera;
  1701→        pinch.centerX = currentCamera.x;
  1702→        pinch.centerY = currentCamera.y;
  1703→        pinch.active = true;
  1704→        return;
  1705→      }
  1706→
  1707→      // Single pointer = pan
  1708→      if (pinch.pointers.size === 1) {
  1709→        // Stop any active momentum and zoom animation
  1710→        stopMomentum();
  1711→        stopZoomAnimation();
  1712→
  1713→        // Get camera position from store (always current, no stale closures)
  1714→        const currentCamera = canvasStore.getState().viewport.camera;
  1715→
  1716→        // Track pointer down position for click detection (F019)
  1717→        pointerDownPosRef.current = { x: e.clientX, y: e.clientY };
  1718→        pointerMovedRef.current = false;
  1719→
  1720→        // Start pan in store
  1721→        canvasStore.dispatch(
  1722→          canvasActions.viewport.startPan({
  1723→            panStart: { x: e.clientX, y: e.clientY },
  1724→            cameraPosAtPanStart: currentCamera,
  1725→          })
  1726→        );
  1727→
  1728→        // Initialize velocity tracking
  1729→        const now = performance.now();
  1730→        lastPointerPosRef.current = { x: e.clientX, y: e.clientY, time: now };
