  1732→      }
  1733→
  1734→      (e.target as HTMLElement).setPointerCapture(e.pointerId);
  1735→    },
  1736→    [zoom, isInitialized, stopMomentum, stopZoomAnimation]
  1737→  );
  1738→
  1739→  /**
  1740→   * Handle hover detection (F018)
  1741→   * Updates hovered task based on mouse position
  1742→   */
  1743→  const updateHover = useCallback(
  1744→    (e: React.PointerEvent) => {
  1745→      // Only update hover when not panning (avoid expensive calculations during drag)
  1746→      const state = canvasStore.getState();
  1747→      if (state.viewport.isPanning) {
  1748→        // Clear hover during panning
  1749→        if (state.interaction.hoveredTaskId !== null) {
  1750→          canvasStore.dispatch(canvasActions.interaction.setHoveredTask(null));
  1751→        }
  1752→        return;
  1753→      }
  1754→
  1755→      // Get container rect for coordinate conversion
  1756→      const container = containerRef.current;
  1757→      if (!container) return;
  1758→
  1759→      const rect = container.getBoundingClientRect();
  1760→      const camera = state.viewport.camera;
  1761→
  1762→      // Find task under cursor
  1763→      const taskId = findTaskAtPosition(
  1764→        e.clientX,
  1765→        e.clientY,
  1766→        rect,
  1767→        camera.x,
  1768→        camera.y,
  1769→        zoom,
  1770→        canvasSize.width,
  1771→        canvasSize.height,
  1772→        tasks
  1773→      );
  1774→
  1775→      // Only update if changed (avoid unnecessary state updates)
  1776→      if (taskId !== state.interaction.hoveredTaskId) {
  1777→        canvasStore.dispatch(canvasActions.interaction.setHoveredTask(taskId));
  1778→      }
  1779→    },
  1780→    [zoom, canvasSize, tasks]
  1781→  );
  1782→
  1783→  /**
  1784→   * Handle pan move / pinch move
  1785→   *
  1786→   * Now uses canvasStore for pan state - values always current
  1787→   */
  1788→  const handlePointerMove = useCallback(
  1789→    (e: React.PointerEvent) => {
  1790→      const pinch = pinchRef.current;
  1791→
  1792→      // Update pointer position
  1793→      if (pinch.pointers.has(e.pointerId)) {
  1794→        pinch.pointers.set(e.pointerId, { x: e.clientX, y: e.clientY });
  1795→      }
  1796→
  1797→      // Handle pinch gesture
  1798→      if (pinch.active && pinch.pointers.size === 2) {
  1799→        const pointers = Array.from(pinch.pointers.values());
  1800→        const dx = pointers[0].x - pointers[1].x;
  1801→        const dy = pointers[0].y - pointers[1].y;
  1802→        const currentDistance = Math.sqrt(dx * dx + dy * dy);
  1803→
  1804→        if (pinch.initialDistance > 0) {
  1805→          const scale = currentDistance / pinch.initialDistance;
  1806→          const centerX = (pointers[0].x + pointers[1].x) / 2;
  1807→          const centerY = (pointers[0].y + pointers[1].y) / 2;
  1808→          handlePinchZoom(scale, centerX, centerY);
  1809→        }
  1810→        return;
  1811→      }
  1812→
  1813→      // Update hover state (F018) - always run to update cursor
  1814→      updateHover(e);
  1815→
  1816→      // Handle pan - get current state from store
  1817→      const state = canvasStore.getState();
  1818→      if (!state.viewport.isPanning) return;
  1819→
  1820→      const dx = (e.clientX - state.viewport.panStart.x) / zoom;
  1821→      const dy = (e.clientY - state.viewport.panStart.y) / zoom;
  1822→
  1823→      // Detect significant movement (F019: to distinguish click from pan)
  1824→      // Using 8px threshold - movement greater than this is a pan, not a click
  1825→      // Higher threshold helps with touchpad/mouse precision issues
  1826→      const moveX = e.clientX - pointerDownPosRef.current.x;
  1827→      const moveY = e.clientY - pointerDownPosRef.current.y;
  1828→      const moveDistance = Math.sqrt(moveX * moveX + moveY * moveY);
  1829→      if (moveDistance > 8) {
  1830→        pointerMovedRef.current = true;
  1831→      }
  1832→
  1833→      const newX = state.viewport.cameraPosAtPanStart.x - dx;
  1834→      const newY = state.viewport.cameraPosAtPanStart.y + dy;
  1835→
  1836→      const clamped = clampCameraToWorld(newX, newY, zoom);
  1837→
  1838→      // Update pan in store
  1839→      canvasStore.dispatch(canvasActions.viewport.updatePan({ camera: clamped }));
  1840→      notifyViewportChange(clamped.x, clamped.y, zoom);
  1841→
  1842→      // Track velocity samples for momentum
  1843→      const now = performance.now();
  1844→      const worldDx = (e.clientX - lastPointerPosRef.current.x) / zoom;
  1845→      const worldDy = (e.clientY - lastPointerPosRef.current.y) / zoom;
  1846→
  1847→      velocitySamplesRef.current.push({
  1848→        x: worldDx,
  1849→        y: worldDy,
  1850→        time: now,
  1851→      });
  1852→
  1853→      // Keep only recent samples
  1854→      if (velocitySamplesRef.current.length > MOMENTUM_VELOCITY_SAMPLES * 2) {
  1855→        velocitySamplesRef.current = velocitySamplesRef.current.slice(-MOMENTUM_VELOCITY_SAMPLES);
  1856→      }
  1857→
  1858→      lastPointerPosRef.current = { x: e.clientX, y: e.clientY, time: now };
  1859→    },
  1860→    [zoom, clampCameraToWorld, notifyViewportChange, handlePinchZoom, updateHover]
  1861→  );
  1862→
  1863→  /**
  1864→   * Handle pan end / pinch end
  1865→   *
  1866→   * Now uses canvasStore for pan state
  1867→   */
  1868→  const handlePointerUp = useCallback(
  1869→    (e: React.PointerEvent) => {
  1870→      const pinch = pinchRef.current;
  1871→
  1872→      // Remove pointer from tracking
  1873→      pinch.pointers.delete(e.pointerId);
  1874→
  1875→      // Release pointer capture
  1876→      try {
  1877→        (e.target as HTMLElement).releasePointerCapture(e.pointerId);
  1878→      } catch {
  1879→        // Ignore if capture was already released
  1880→      }
  1881→
  1882→      // Reset pinch state when all pointers released
  1883→      if (pinch.pointers.size < 2) {
  1884→        pinch.active = false;
  1885→        pinch.initialDistance = 0;
  1886→      }
  1887→
  1888→      // Handle pan end with momentum - check store for isPanning
  1889→      const state = canvasStore.getState();
  1890→      if (state.viewport.isPanning && pinch.pointers.size === 0) {
  1891→        canvasStore.dispatch(canvasActions.viewport.endPan());
  1892→
  1893→        // BUG-008: Momentum disabled - was causing elastic/jumping behavior
  1894→        // The momentum animation had stale closure issues despite the cameraPosRef fix
  1895→        // TODO: Reimplement with proper state synchronization if momentum UX is desired
  1896→        // Original code:
  1897→        // const { vx, vy } = calculateAverageVelocity();
  1898→        // const speed = Math.sqrt(vx ** 2 + vy ** 2);
  1899→        // if (speed > 0.01) { startMomentum(vx, vy); }
  1900→      }
  1901→    },
  1902→    [calculateAverageVelocity, startMomentum]
  1903→  );
  1904→
  1905→  /**
  1906→   * Handle double-click to zoom in at click location
  1907→   * Zooms 2x toward the clicked point with smooth animation
  1908→   *
  1909→   * Now uses animateZoomTo which uses the canvasStore
  1910→   */
  1911→  const handleDoubleClick = useCallback(
  1912→    (e: React.MouseEvent) => {
  1913→      if (!isInitialized) return;
  1914→
  1915→      // Stop any active animations
  1916→      stopMomentum();
  1917→      stopZoomAnimation();
  1918→
  1919→      const rect = containerRef.current?.getBoundingClientRect();
  1920→      if (!rect) return;
  1921→
  1922→      // Get current camera from store
  1923→      const currentCamera = canvasStore.getState().viewport.camera;
  1924→
  1925→      // Calculate target zoom (2x, clamped to MAX_ZOOM)
  1926→      const targetZoom = Math.min(zoom * 2, MAX_ZOOM);
  1927→      if (Math.abs(targetZoom - zoom) < 0.001) return;
  1928→
  1929→      // Cursor position relative to canvas center
  1930→      const cursorX = e.clientX - rect.left - rect.width / 2;
  1931→      const cursorY = e.clientY - rect.top - rect.height / 2;
  1932→
  1933→      // Calculate target camera position (zoom toward click point)
  1934→      const worldX = cursorX / zoom + currentCamera.x;
  1935→      const worldY = -cursorY / zoom + currentCamera.y;
  1936→      const newCameraX = worldX - cursorX / targetZoom;
  1937→      const newCameraY = worldY + cursorY / targetZoom;
  1938→
  1939→      const clamped = clampCameraToWorld(newCameraX, newCameraY, targetZoom);
  1940→
  1941→      // Animate with slightly longer duration for double-click (350ms)
  1942→      animateZoomTo(targetZoom, clamped.x, clamped.y, 350);
  1943→    },
  1944→    [zoom, isInitialized, stopMomentum, stopZoomAnimation, clampCameraToWorld, animateZoomTo]
  1945→  );
  1946→
  1947→  /**
  1948→   * Handle click to select/deselect task (F019)
  1949→   * Clicks on tasks select them, clicks on background deselect
  1950→   */
  1951→  const handleClick = useCallback(
  1952→    (e: React.MouseEvent) => {
  1953→      if (!isInitialized) return;
  1954→
  1955→      // Don't process clicks that are part of a pan gesture
  1956→      // If pointer moved significantly between down and up, this is a pan, not a click
  1957→      if (pointerMovedRef.current) {
  1958→        return;
  1959→      }
  1960→
  1961→      const state = canvasStore.getState();
  1962→
  1963→      const container = containerRef.current;
  1964→      if (!container) return;
  1965→
  1966→      const rect = container.getBoundingClientRect();
  1967→      const camera = state.viewport.camera;
  1968→
  1969→      // Find task at click position
  1970→      const taskId = findTaskAtPosition(
  1971→        e.clientX,
  1972→        e.clientY,
  1973→        rect,
  1974→        camera.x,
  1975→        camera.y,
  1976→        zoom,
  1977→        canvasSize.width,
  1978→        canvasSize.height,
  1979→        tasks
  1980→      );
  1981→
  1982→      if (taskId) {
  1983→        // Toggle selection: if clicking same task, deselect; otherwise, select
  1984→        if (taskId === state.interaction.selectedTaskId) {
  1985→          canvasStore.dispatch(canvasActions.interaction.clearSelection());
  1986→        } else {
  1987→          canvasStore.dispatch(canvasActions.interaction.setSelectedTask(taskId));
  1988→        }
  1989→      } else {
  1990→        // Clicked on background: clear selection
  1991→        if (state.interaction.selectedTaskId !== null) {
  1992→          canvasStore.dispatch(canvasActions.interaction.clearSelection());
  1993→        }
  1994→      }
  1995→    },
  1996→    [isInitialized, zoom, canvasSize, tasks]
  1997→  );
  1998→
  1999→  /**
  2000→   * Handle pointer leave - clear pan and hover state
  2001→   */
  2002→  const handlePointerLeave = useCallback(
  2003→    (e: React.PointerEvent) => {
  2004→      // Handle pan end
  2005→      handlePointerUp(e);
  2006→      // Clear hover state (F018)
  2007→      canvasStore.dispatch(canvasActions.interaction.clearHover());
  2008→    },
  2009→    [handlePointerUp]
  2010→  );
  2011→
  2012→  // Determine cursor style: grabbing when panning, pointer when hovering task, grab otherwise
  2013→  const cursorStyle = isPanning ? 'grabbing' : isHoverable ? 'pointer' : 'grab';
  2014→
  2015→  // Generate aria-label with current state information (F022)
  2016→  const ariaLabel = `Metro maintenance planning canvas. ${LOD_LABELS[lod]}. ${formatZoomForAria(zoom)}. Use Tab to navigate tasks, Enter to select, Arrow keys to pan, plus minus to zoom.`;
  2017→
  2018→  return (
  2019→    <div
  2020→      ref={containerRef}
  2021→      // F022: ARIA attributes for accessibility
  2022→      role="application"
  2023→      aria-label={ariaLabel}
  2024→      aria-roledescription="Interactive maintenance scheduling canvas"
  2025→      style={{
  2026→        width: '100%',
  2027→        height: '100%',
  2028→        cursor: cursorStyle,
  2029→        touchAction: 'none',
  2030→        position: 'relative', // For absolute positioning of live region
  2031→      }}
  2032→      onPointerDown={handlePointerDown}
  2033→      onPointerMove={handlePointerMove}
  2034→      onPointerUp={handlePointerUp}
  2035→      onPointerLeave={handlePointerLeave}
  2036→      onDoubleClick={handleDoubleClick}
  2037→      onClick={handleClick}
  2038→    >
  2039→      {/* F022: ARIA Live Region for screen reader announcements */}
  2040→      <div
  2041→        ref={ariaLiveRef}
  2042→        role="status"
  2043→        aria-live="polite"
  2044→        aria-atomic="true"
  2045→        style={{
  2046→          position: 'absolute',
  2047→          width: '1px',
  2048→          height: '1px',
  2049→          padding: '0',
  2050→          margin: '-1px',
  2051→          overflow: 'hidden',
  2052→          clip: 'rect(0, 0, 0, 0)',
  2053→          whiteSpace: 'nowrap',
  2054→          border: '0',
  2055→        }}
  2056→      />
  2057→      <Canvas
  2058→        gl={{ antialias: true, alpha: false }}
  2059→        style={{ background: '#f4f4f5' }}
  2060→        orthographic
  2061→        camera={{
  2062→          position: [cameraPos.x, cameraPos.y, 100],
  2063→          zoom: zoom,
  2064→          near: 0.1,
  2065→          far: 1000,
  2066→        }}
  2067→      >
  2068→        <CameraController
  2069→          cameraX={cameraPos.x}
  2070→          cameraY={cameraPos.y}
  2071→          zoom={zoom}
