        if (e.shiftKey) {
          // Shift+Tab: Move to previous task
          if (currentFocusedTaskId) {
            const currentIndex = visibleTasks.findIndex((t) => t.id === currentFocusedTaskId);
            if (currentIndex > 0) {
              nextTaskId = visibleTasks[currentIndex - 1].id;
            } else {
              // Wrap to last visible task
              nextTaskId = visibleTasks[visibleTasks.length - 1].id;
            }
          } else {
            // No focus: start from last visible task
            nextTaskId = visibleTasks[visibleTasks.length - 1].id;
          }
        } else {
          // Tab: Move to next task
          if (currentFocusedTaskId) {
            const currentIndex = visibleTasks.findIndex((t) => t.id === currentFocusedTaskId);
            if (currentIndex >= 0 && currentIndex < visibleTasks.length - 1) {
              nextTaskId = visibleTasks[currentIndex + 1].id;
            } else {
              // Wrap to first visible task
              nextTaskId = visibleTasks[0].id;
            }
          } else {
            // No focus: start from first visible task
            nextTaskId = visibleTasks[0].id;
          }
        }

